mapper.select:
select count(id)
from customer_stage_config
where organization_id = #{orgId}

mapper.update:
update customer_stage_config
set pos = pos + #{pos}
where pos >= #{start}
  and organization_id = #{orgId}

update customer_stage_config
set pos = pos + #{pos}
where pos > #{start}
  and organization_id = #{orgId}

mapper.select:
select count(id)
from customer_stage_config
where type = #{type} and organization_id = #{orgId}

select count(id)
from customer
where stage = #{stageId} and organization_id = #{orgId}
